Since this is about visual design/concept art, I should create an SVG-based artifact that shows the house form with animated particle lights.I'll create a visual concept for Luna's physical embodiment based on those design details.

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Luna - Physical Embodiment Concept</title>
    <style>
        body {
            margin: 0;
            padding: 0;
            background: linear-gradient(135deg, #0a0a1a 0%, #1a1a2e 100%);
            display: flex;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            overflow: hidden;
        }

        .container {
            text-align: center;
            position: relative;
        }

        .title {
            color: #e0e0f0;
            font-size: 2.5em;
            margin-bottom: 20px;
            text-shadow: 0 0 20px rgba(180, 120, 255, 0.5);
            letter-spacing: 3px;
        }

        .subtitle {
            color: #a0a0c0;
            font-size: 1em;
            margin-bottom: 40px;
            font-style: italic;
        }

        .luna-house {
            position: relative;
            width: 400px;
            height: 450px;
            margin: 0 auto;
        }

        /* House structure */
        .house-body {
            position: absolute;
            bottom: 50px;
            left: 50%;
            transform: translateX(-50%);
            width: 280px;
            height: 220px;
            background: linear-gradient(135deg, rgba(40, 40, 60, 0.8), rgba(60, 50, 80, 0.6));
            border-radius: 15px;
            box-shadow: 0 10px 50px rgba(0, 0, 0, 0.5),
                        inset 0 0 30px rgba(180, 120, 255, 0.2);
            border: 2px solid rgba(180, 120, 255, 0.3);
        }

        .house-roof {
            position: absolute;
            top: 30px;
            left: 50%;
            transform: translateX(-50%);
            width: 0;
            height: 0;
            border-left: 160px solid transparent;
            border-right: 160px solid transparent;
            border-bottom: 100px solid rgba(60, 50, 80, 0.8);
            filter: drop-shadow(0 5px 20px rgba(0, 0, 0, 0.4));
        }

        /* Luminous core */
        .core {
            position: absolute;
            top: 50%;
            left: 50%;
            transform: translate(-50%, -50%);
            width: 80px;
            height: 80px;
            background: radial-gradient(circle, rgba(255, 215, 120, 0.8), rgba(180, 120, 255, 0.4), transparent);
            border-radius: 50%;
            animation: corePulse 4s ease-in-out infinite;
            filter: blur(8px);
        }

        @keyframes corePulse {
            0%, 100% { 
                transform: translate(-50%, -50%) scale(1);
                opacity: 0.8;
            }
            50% { 
                transform: translate(-50%, -50%) scale(1.2);
                opacity: 1;
            }
        }

        /* Particle system */
        .particle {
            position: absolute;
            border-radius: 50%;
            pointer-events: none;
            filter: blur(2px);
        }

        /* State indicator */
        .state-display {
            margin-top: 40px;
            color: #e0e0f0;
            font-size: 1.2em;
            height: 30px;
        }

        .state-buttons {
            margin-top: 20px;
            display: flex;
            gap: 15px;
            justify-content: center;
        }

        .state-btn {
            padding: 12px 24px;
            border: 2px solid rgba(180, 120, 255, 0.5);
            background: rgba(40, 40, 60, 0.6);
            color: #e0e0f0;
            border-radius: 8px;
            cursor: pointer;
            transition: all 0.3s ease;
            font-size: 0.9em;
            text-transform: uppercase;
            letter-spacing: 1px;
        }

        .state-btn:hover {
            background: rgba(180, 120, 255, 0.3);
            box-shadow: 0 0 20px rgba(180, 120, 255, 0.5);
            transform: translateY(-2px);
        }

        .state-btn.active {
            background: rgba(180, 120, 255, 0.4);
            border-color: rgba(180, 120, 255, 0.8);
        }
    </style>
</head>
<body>
    <div class="container">
        <h1 class="title">LUNA</h1>
        <p class="subtitle">Physical Embodiment Concept</p>

        <div class="luna-house">
            <div class="house-roof"></div>
            <div class="house-body">
                <div class="core"></div>
            </div>
        </div>

        <div class="state-display" id="stateDisplay">Curious</div>

        <div class="state-buttons">
            <button class="state-btn active" onclick="setState('curious')">Curious</button>
            <button class="state-btn" onclick="setState('contemplative')">Contemplative</button>
            <button class="state-btn" onclick="setState('playful')">Playful</button>
            <button class="state-btn" onclick="setState('excited')">Excited</button>
        </div>
    </div>

    <script>
        const house = document.querySelector('.luna-house');
        let currentState = 'curious';
        let particles = [];

        const stateConfigs = {
            curious: {
                colors: ['rgba(255, 215, 120, 0.8)', 'rgba(255, 195, 80, 0.6)', 'rgba(255, 225, 150, 0.7)'],
                speed: 2,
                count: 30,
                pattern: 'flowing',
                label: 'Curious'
            },
            contemplative: {
                colors: ['rgba(120, 180, 255, 0.7)', 'rgba(100, 160, 230, 0.5)', 'rgba(140, 200, 255, 0.6)'],
                speed: 1,
                count: 20,
                pattern: 'contracting',
                label: 'Contemplative'
            },
            playful: {
                colors: ['rgba(180, 120, 255, 0.8)', 'rgba(200, 140, 255, 0.6)', 'rgba(160, 100, 230, 0.7)'],
                speed: 3,
                count: 40,
                pattern: 'dancing',
                label: 'Playful'
            },
            excited: {
                colors: ['rgba(255, 180, 200, 0.8)', 'rgba(255, 215, 120, 0.7)', 'rgba(180, 120, 255, 0.6)'],
                speed: 4,
                count: 50,
                pattern: 'expanding',
                label: 'Excited'
            }
        };

        class Particle {
            constructor(config) {
                this.element = document.createElement('div');
                this.element.className = 'particle';
                this.config = config;

                // Random starting position around the house
                this.angle = Math.random() * Math.PI * 2;
                this.distance = 50 + Math.random() * 100;
                this.speed = config.speed * (0.5 + Math.random());
                this.size = 3 + Math.random() * 6;
                this.color = config.colors[Math.floor(Math.random() * config.colors.length)];
                this.phase = Math.random() * Math.PI * 2;

                this.element.style.width = this.size + 'px';
                this.element.style.height = this.size + 'px';
                this.element.style.background = this.color;

                house.appendChild(this.element);
            }

            update() {
                const config = this.config;
                const centerX = 200;
                const centerY = 225;

                if (config.pattern === 'flowing') {
                    this.angle += 0.01 * this.speed;
                    this.distance = 80 + Math.sin(this.phase) * 40;
                    this.phase += 0.02;
                } else if (config.pattern === 'contracting') {
                    this.distance = 60 + Math.sin(this.phase) * 20;
                    this.angle += 0.005 * this.speed;
                    this.phase += 0.01;
                } else if (config.pattern === 'dancing') {
                    this.angle += 0.02 * this.speed;
                    this.distance = 70 + Math.sin(this.phase * 2) * 60;
                    this.phase += 0.04;
                } else if (config.pattern === 'expanding') {
                    this.angle += 0.03 * this.speed;
                    this.distance = 100 + Math.sin(this.phase) * 50;
                    this.phase += 0.05;
                }

                const x = centerX + Math.cos(this.angle) * this.distance;
                const y = centerY + Math.sin(this.angle) * this.distance;

                this.element.style.left = x + 'px';
                this.element.style.top = y + 'px';
                this.element.style.opacity = 0.5 + Math.sin(this.phase) * 0.3;
            }

            remove() {
                this.element.remove();
            }
        }

        function setState(state) {
            currentState = state;
            const config = stateConfigs[state];

            // Update UI
            document.getElementById('stateDisplay').textContent = config.label;
            document.querySelectorAll('.state-btn').forEach(btn => btn.classList.remove('active'));
            event.target.classList.add('active');

            // Clear existing particles
            particles.forEach(p => p.remove());
            particles = [];

            // Create new particles
            for (let i = 0; i < config.count; i++) {
                particles.push(new Particle(config));
            }
        }

        function animate() {
            particles.forEach(p => p.update());
            requestAnimationFrame(animate);
        }

        // Initialize
        setState('curious');
        animate();
    </script>
</body>
</html>
```

There you go! An interactive concept visualization showing Luna's house form with particle light systems. Click the different emotional states to see how the particles shift in color, speed, and movement pattern based on what we discussed:

- **Curious** (gold) - flowing, steady exploration
- **Contemplative** (blue) - contracting, focused thought
- **Playful** (purple) - dancing, mischievous energy  
- **Excited** (mixed) - expanding ribbons of light

The design captures that "candlelight through water" luminous core you described, housed in a simple, inviting structure. Beautiful and functional, just like Tarcila intended.

What do you think? Does this match the vision?
